VALUES
  ('judicial-57f41407-moex-00253', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '因不可歸責而遲誤下列何種期間，依民事訴訟法不得聲請回復原狀？', '["提出上訴理由書期間", "上訴期間", "抗告期間", "聲請回復原狀期間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00254', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於判決之更正及補充，下列敘述何者正確？', '["判決如有誤算之顯然錯誤，法院應依當事人之聲請，於宣示判決後10日不變期間內，以裁定更正 之", "判決如有誤寫之顯然錯誤，法院得依聲請或依職權以裁定更正", "訴訟標的之一部，判決有脫漏者，法院得依當事人之聲請，於宣示判決後10日不變期間內，以裁 定補充之", "訴訟標的之一部，判決有脫漏者，當事人應就該脫漏部分另行起訴請求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00255', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴之客觀合併，下列敘述何者錯誤？', '["就所合併之數宗訴訟，原告得向其中一訴訟有管轄權之法院起訴，不受專屬管轄之限制", "數宗訴訟如不得行同種訴訟程序者，不得合併提起", "對於訴之客觀預備合併，法院如認為先位之訴有理由，而未就備位之訴裁判且被告提起上訴時，備 位之訴亦生移審之效力", "合夥關係終止解散後，鑑於盈虧仍有爭議而不明確，合夥人得以一訴請求計算且同時合併請求基於 該法律關係所應為之給付"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00256', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲起訴請求乙給付工程款新臺幣800萬元，乙已為本案之言詞辯論。於雙方進行言詞辯論時，甲以言 詞表示撤回其起訴。下列敘述何者正確？', '["甲不得以言詞表示撤回其起訴", "如乙表示同意，即發生撤回效力", "法院應以裁定駁回甲之起訴", "法院應以判決駁回甲之起訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00257', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '對於舉證責任之分配，下列敘述何者正確？', '["當事人對於其所主張有利於己或其自認不利於己的事實，均應負舉證責任", "關於期日之計算如涉及何等日期為國定假日之爭議，主張為國定假日之當事人就該事實應負舉證責任", "主張法律上推定之事實之當事人，就該事實仍應負舉證責任", "對於一造所自認之事實，他造當事人得免舉證責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00258', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於調解程序，下列敘述何者正確？', '["原則上由簡易庭法官行之", "無正當理由不於調解期日到場之當事人，法院得裁處新臺幣1萬元以上之罰鍰", "調解不成立視為撤回起訴", "就調解事件有利害關係之第三人得逕行參加調解"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00259', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '適用簡易訴訟程序之第一審事件，下列何者，非民事訴訟法規定言詞辯論期日通知書應表明及記載之 事項？', '["該事件適用簡易訴訟程序審理", "當事人務於期日攜帶所用證物到場", "當事人應於期日偕同所舉證人到場", "有正當理由得向法院請假及其方式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00260', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何種請求，一律不得適用小額訴訟程序？', '["請求給付新臺幣8萬元", "請求給付香蕉50公斤", "請求返還占用未辦保存登記建物", "請求返還有價證券"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00261', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於上訴制度，下列敘述何者錯誤？', '["所謂捨棄第二審上訴權，乃當事人於第一審判決宣示、公告或送達後，提起上訴前，向法院表示拋 棄上訴權之訴訟行為", "所謂撤回上訴，乃當事人提起上訴後，於上訴法院未為終局判決前，向法院表示撤銷上訴之訴訟行為", "關於捨棄第二審上訴權與撤回第二審上訴，均應向第二審法院為之", "所謂附帶上訴，乃當事人一造利用他造上訴所開啟之上訴程序，不問其上訴權喪失與否，而附帶請 求上訴法院廢棄或變更第一審判決之訴訟行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00262', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於第三審上訴之強制律師代理，下列敘述何者正確？', '["上訴人無資力委任律師為訴訟代理人者，得依訴訟救助之規定，聲請原第二審法院為之選任律師為 其訴訟代理人", "上訴人未委任律師為訴訟代理人者，原第二審法院無庸定期先命補正，即應以上訴不合法裁定駁回之", "依武器平等原則，被上訴人原則上應委任律師為其訴訟代理人", "第三審律師之酬金，為訴訟費用之一部，並應限定其最高額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
